<script setup lang="ts">
import { ref } from 'vue'
import { useRouter } from 'vue-router'
import GameLayout from '@/layouts/GameLayout.vue'
import PageFrame from '@/components/common/PageFrame.vue'
import WeaponIcon from '@/components/common/WeaponIcon.vue'
import { weapons, type Weapon } from '@/data/weapons'

const router = useRouter()
function goBack() {
  if (window.history.length > 1) router.back()
  else router.push('/huzhong')
}

// 6 个槽位:主手/副手/头/身/鞋/饰品
const slotMeta = [
  { key: 'main', label: '主手', emoji: '🗡️' },
  { key: 'off', label: '副手', emoji: '🛡️' },
  { key: 'head', label: '头部', emoji: '👑' },
  { key: 'body', label: '衣服', emoji: '👕' },
  { key: 'feet', label: '鞋子', emoji: '👢' },
  { key: 'ring', label: '饰品', emoji: '💍' },
]

const equipped = ref<Record<string, Weapon | null>>({
  main: null,
  off: null,
  head: null,
  body: null,
  feet: null,
  ring: null,
})

const activeSlot = ref<string>('main')

function equip(w: Weapon) {
  equipped.value[activeSlot.value] = w
}
function unequip() {
  equipped.value[activeSlot.value] = null
}
</script>

<template>
  <GameLayout>
    <!-- 返回壶中天地 -->
    <button
      type="button"
      class="absolute left-3 top-[68px] z-30 px-3 py-1.5 rounded-lg bg-black/70 hover:bg-black/90 border border-amber-700/60 text-amber-100 text-[12px] font-bold flex items-center gap-1 transition active:scale-95 shadow"
      aria-label="返回壶中天地"
      @click="goBack"
    >
      ← 返回壶中天地
    </button>
    <PageFrame title="装备" subtitle="Equipment · 6 槽位 × 25 武器 · 点击槽位再选武器" emoji="⚔️">
      <!-- 6 装备槽 -->
      <div class="grid grid-cols-6 gap-3 mb-4">
        <button
          v-for="s in slotMeta"
          :key="s.key"
          class="flex flex-col items-center gap-1 p-2 rounded-lg border-2 transition"
          :class="
            activeSlot === s.key
              ? 'border-amber-400 bg-amber-900/30'
              : 'border-amber-700/40 bg-black/40 hover:border-amber-500/70'
          "
          @click="activeSlot = s.key"
        >
          <WeaponIcon v-if="equipped[s.key]" :weapon="equipped[s.key]!" tier="upgrade" :size="56" />
          <div
            v-else
            class="w-14 h-14 rounded-lg border-2 border-dashed border-amber-700/50 flex items-center justify-center text-2xl text-amber-600/60"
          >
            {{ s.emoji }}
          </div>
          <div class="text-[11px] text-amber-200 font-bold">{{ s.label }}</div>
        </button>
      </div>

      <!-- 当前槽位状态条 -->
      <div
        v-if="equipped[activeSlot]"
        class="mb-3 flex items-center gap-2 px-3 py-2 rounded-lg bg-emerald-900/30 border border-emerald-700/40"
      >
        <span class="text-emerald-200 text-[12px] flex-1">
          ✅ 已装备:{{ equipped[activeSlot]!.base }}
        </span>
        <button
          class="px-2 py-0.5 rounded text-[11px] bg-rose-700/60 text-white hover:bg-rose-700"
          @click="unequip"
        >
          卸下
        </button>
      </div>

      <!-- 武器选择列表 -->
      <div class="rounded-lg bg-black/40 border border-amber-700/30 p-3">
        <div class="text-amber-200 text-[14px] font-bold mb-2">🎒 武器库({{ weapons.length }})</div>
        <div class="grid grid-cols-5 gap-2">
          <button
            v-for="w in weapons"
            :key="w.id"
            class="flex flex-col items-center gap-1 p-1.5 rounded bg-black/30 border border-amber-700/20 hover:border-amber-400 hover:bg-black/60 transition"
            @click="equip(w)"
          >
            <WeaponIcon :weapon="w" :size="48" />
            <div class="text-[11px] text-amber-100 truncate max-w-full">
              {{ w.base }}
            </div>
          </button>
        </div>
      </div>
    </PageFrame>
  </GameLayout>
</template>
